import Link from "next/link";
import styles from "./navigation.module.css";

function Navigation() {
  return (
    <div className={styles.navigation}>
      <Link href="/">
        <a>Güngör</a>
      </Link>
      <ul className={styles.links}>
        <li className={styles.link}>
          <Link href="/about">
            <a>About Us</a>
          </Link>
        </li>
        <li className={styles.link}>
          <Link href="/blog/hello-world">
            <a>Blog</a>
          </Link>
        </li>
      </ul>
    </div>
  );
}

export default Navigation;
